import type { CardConfig } from "../contracts/types";

export function normalizeSavedConfigStatic(config: CardConfig): boolean {
  if (config.type === "internal") {
    config.type = "internal";
    config.options = "";
    return true;
  }
  if (config.type === "light_brightness") {
    config.sensor = "";
    config.type = "light_brightness";
    config.options = "";
    return true;
  }
  if (config.type === "light_switch") {
    config.sensor = "";
    config.unit = "";
    config.type = "light_switch";
    config.precision = "";
    config.options = "";
    return true;
  }
  if (config.type === "light_temperature") {
    config.type = "light_temperature";
    config.options = "";
    return true;
  }
  if (config.type === "push") {
    config.type = "push";
    config.options = "";
    return true;
  }
  if (config.type === "screen_lock") {
    config.entity = "";
    config.label = "";
    config.icon = "Lock";
    config.icon_on = "Lock Open";
    config.sensor = "";
    config.unit = "";
    config.type = "screen_lock";
    config.precision = "";
    config.options = "";
    return true;
  }
  if (config.type === "slider") {
    config.sensor = "";
    config.type = "slider";
    config.options = "";
    return true;
  }
  return false;
}
